import { FocusEventHandler, type SyntheticEvent, type KeyboardEvent as ReactKeyboardEvent } from 'react';
import type { PointerType } from './pointer.js';
/**
 * @public
 */
export interface PressEvent {
    /** The type of press event being fired. */
    type: 'pressstart' | 'pressend' | 'pressup' | 'press';
    /** The pointer type that triggered the press event. */
    pointerType: PointerType;
    /** The target element of the press event. */
    target: Element;
    /** Whether the shift keyboard modifier was held during the press event. */
    shiftKey: boolean;
    /** Whether the ctrl keyboard modifier was held during the press event. */
    ctrlKey: boolean;
    /** Whether the meta keyboard modifier was held during the press event. */
    metaKey: boolean;
    /** Whether the alt keyboard modifier was held during the press event. */
    altKey: boolean;
}
/**
 * @public
 */
export interface FocusEvents {
    /** Handler that is called when the element receives focus. */
    onFocus?: FocusEventHandler<HTMLButtonElement | Element> | undefined;
    /** Handler that is called when the element loses focus. */
    onBlur?: FocusEventHandler<HTMLButtonElement | Element> | undefined;
    /** Handler that is called when the element's focus status changes. */
    onFocusChange?: (isFocused: boolean) => void;
}
/**
 * @public
 */
export type BaseEvent<T extends SyntheticEvent> = T & {
    continuePropagation(): void;
};
/**
 * @public
 */
export type KeyboardEvent = BaseEvent<ReactKeyboardEvent<any>>;
/**
 * @public
 */
export interface KeyboardEvents {
    /** Handler that is called when a key is pressed. */
    onKeyDown?: (e: KeyboardEvent) => void;
    /** Handler that is called when a key is released. */
    onKeyUp?: (e: KeyboardEvent) => void;
}
